# Plan:
# 1. Create a small multi-file boids simulation: index.html, css/style.css, js/boid.js, js/flock.js, js/main.js
# 2. Write files to disk.
# 3. Spawn child agents (delegates) to verify each file contains wiring / expected exports/imports.
# 4. Wait for all checks, inspect results, and finish with a summary and instructions.
#
# Execute immediately.

# 1) Create files
index_html = """<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8" />
  <meta name="viewport" content="width=device-width,initial-scale=1" />
  <title>Boids Simulation</title>
  <link rel="stylesheet" href="css/style.css" />
</head>
<body>
  <canvas id="flockCanvas"></canvas>
  <div id="ui">
    <label>Boid count: <input id="count" type="range" min="20" max="800" value="180" /></label>
    <label>Speed: <input id="speed" type="range" min="1" max="8" value="4" step="0.1" /></label>
    <button id="toggleTrail">Toggle Trail</button>
  </div>
  <script type="module" src="js/main.js"></script>
</body>
</html>
"""

style_css = """:root{
  --bg:#0b1020;
}
html,body{
  height:100%;
  margin:0;
  background:var(--bg);
  color:#eee;
  font-family: system-ui, -apple-system, "Segoe UI", Roboto, "Helvetica Neue", Arial;
}
#flockCanvas{
  display:block;
  width:100%;
  height:100vh;
}
#ui{
  position:fixed;
  left:10px;
  top:10px;
  background:rgba(0,0,0,0.25);
  padding:8px 10px;
  border-radius:8px;
  backdrop-filter: blur(6px);
  display:flex;
  gap:10px;
  align-items:center;
  z-index:10;
}
#ui label{ font-size:13px; color:#fff; }
#ui input[type="range"]{ vertical-align:middle; }
#ui button{
  background:linear-gradient(180deg,#fff2,#ffffff00);
  border:1px solid rgba(255,255,255,0.12);
  color:#fff;
  padding:6px 8px;
  border-radius:6px;
  cursor:pointer;
}
"""

boid_js = """// js/boid.js
export default class Boid {
  constructor(x, y, id=0) {
    this.pos = {x: x, y: y};
    const angle = Math.random() * Math.PI * 2;
    const speed = 2 + Math.random() * 2;
    this.vel = {x: Math.cos(angle) * speed, y: Math.sin(angle) * speed};
    this.acc = {x: 0, y: 0};
    this.maxForce = 0.05;
    this.maxSpeed = 4;
    this.id = id;
  }

  applyForce(f){
    this.acc.x += f.x;
    this.acc.y += f.y;
  }

  // Vector helpers
  static add(a, b){ return {x: a.x + b.x, y: a.y + b.y}; }
  static sub(a, b){ return {x: a.x - b.x, y: a.y - b.y}; }
  static mult(v, s){ return {x: v.x * s, y: v.y * s}; }
  static div(v, s){ return {x: v.x / s, y: v.y / s}; }
  static mag(v){ return Math.hypot(v.x, v.y); }
  static setMag(v, m){
    const mag = Boid.mag(v) || 1;
    return {x: v.x / mag * m, y: v.y / mag * m};
  }
  static limit(v, max){
    const m = Boid.mag(v);
    if (m > max) return Boid.setMag(v, max);
    return v;
  }

  update(){
    this.vel.x += this.acc.x;
    this.vel.y += this.acc.y;
    this.vel = Boid.limit(this.vel, this.maxSpeed);
    this.pos.x += this.vel.x;
    this.pos.y += this.vel.y;
    this.acc.x = 0;
    this.acc.y = 0;
  }

  edges(width, height){
    if (this.pos.x > width) this.pos.x = 0;
    if (this.pos.x < 0) this.pos.x = width;
    if (this.pos.y > height) this.pos.y = 0;
    if (this.pos.y < 0) this.pos.y = height;
  }

  // Behaviors: alignment, cohesion, separation
  align(boids, perception=50){
    let steering = {x:0,y:0}, total=0;
    for (const other of boids){
      const d = Math.hypot(this.pos.x - other.pos.x, this.pos.y - other.pos.y);
      if (other !== this && d < perception){
        steering.x += other.vel.x;
        steering.y += other.vel.y;
        total++;
      }
    }
    if (total > 0){
      steering = Boid.div(steering, total);
      steering = Boid.setMag(steering, this.maxSpeed);
      steering = Boid.sub(steering, this.vel);
      steering = Boid.limit(steering, this.maxForce);
    }
    return steering;
  }

  cohesion(boids, perception=60){
    let steering = {x:0,y:0}, total=0;
    for (const other of boids){
      const d = Math.hypot(this.pos.x - other.pos.x, this.pos.y - other.pos.y);
      if (other !== this && d < perception){
        steering.x += other.pos.x;
        steering.y += other.pos.y;
        total++;
      }
    }
    if (total > 0){
      steering = Boid.div(steering, total);
      steering = Boid.sub(steering, this.pos);
      steering = Boid.setMag(steering, this.maxSpeed);
      steering = Boid.sub(steering, this.vel);
      steering = Boid.limit(steering, this.maxForce);
    }
    return steering;
  }

  separation(boids, perception=30){
    let steering = {x:0,y:0}, total=0;
    for (const other of boids){
      const d = Math.hypot(this.pos.x - other.pos.x, this.pos.y - other.pos.y);
      if (other !== this && d < perception){
        let diff = Boid.sub(this.pos, other.pos);
        if (d !== 0) diff = Boid.div(diff, d); // weight by distance
        steering.x += diff.x;
        steering.y += diff.y;
        total++;
      }
    }
    if (total > 0){
      steering = Boid.div(steering, total);
      steering = Boid.setMag(steering, this.maxSpeed);
      steering = Boid.sub(steering, this.vel);
      steering = Boid.limit(steering, this.maxForce * 1.5);
    }
    return steering;
  }

  flock(boids, weights = {align:1.0, cohesion:1.0, separation:1.5}){
    const a = this.align(boids, 50);
    const c = this.cohesion(boids, 60);
    const s = this.separation(boids, 28);
    this.applyForce(Boid.mult(a, weights.align));
    this.applyForce(Boid.mult(c, weights.cohesion));
    this.applyForce(Boid.mult(s, weights.separation));
  }

  // draw as colorful triangle oriented along velocity
  draw(ctx, hue=180, size=6){
    const angle = Math.atan2(this.vel.y, this.vel.x);
    ctx.save();
    ctx.translate(this.pos.x, this.pos.y);
    ctx.rotate(angle);
    ctx.beginPath();
    ctx.moveTo(size, 0);
    ctx.lineTo(-size * 0.6, size * 0.6);
    ctx.lineTo(-size * 0.6, -size * 0.6);
    ctx.closePath();
    ctx.fillStyle = `hsl(${hue} 95% 55%)`;
    ctx.fill();
    ctx.restore();
  }
}
"""

flock_js = """// js/flock.js
import Boid from './boid.js';

export function createFlock(count, width, height){
  const boids = [];
  for (let i=0;i<count;i++){
    const x = Math.random() * width;
    const y = Math.random() * height;
    const b = new Boid(x,y,i);
    boids.push(b);
  }
  return boids;
}
"""

main_js = """// js/main.js
import Boid from './boid.js';
import { createFlock } from './flock.js';

const canvas = document.getElementById('flockCanvas');
const ctx = canvas.getContext('2d');

let width = 0, height = 0;
function resize(){
  const dpr = window.devicePixelRatio || 1;
  width = Math.floor(window.innerWidth);
  height = Math.floor(window.innerHeight);
  canvas.width = Math.floor(width * dpr);
  canvas.height = Math.floor(height * dpr);
  canvas.style.width = width + 'px';
  canvas.style.height = height + 'px';
  ctx.setTransform(dpr,0,0,dpr,0,0);
}
window.addEventListener('resize', resize);

let boids = [];
let countControl = null;
let speedControl = null;
let trail = false;
let last = performance.now();

function init(){
  resize();
  countControl = document.getElementById('count');
  speedControl = document.getElementById('speed');
  const toggleTrailBtn = document.getElementById('toggleTrail');
  toggleTrailBtn.addEventListener('click', ()=>{ trail = !trail; });

  const initialCount = parseInt(countControl.value,10) || 180;
  boids = createFlock(initialCount, width, height);

  countControl.addEventListener('input', ()=>{
    const n = parseInt(countControl.value,10);
    if (n > boids.length){
      const add = n - boids.length;
      for (let i=0;i<add;i++){
        boids.push(new Boid(Math.random()*width, Math.random()*height, boids.length));
      }
    } else {
      boids.length = n;
    }
  });

  requestAnimationFrame(loop);
}

function loop(t){
  const dt = Math.min(50, t - last);
  last = t;

  // background / trail
  if (!trail){
    ctx.clearRect(0,0,width,height);
    // subtle vignette background
    ctx.fillStyle = 'rgba(10,12,24,0.08)';
    ctx.fillRect(0,0,width,height);
  } else {
    ctx.fillStyle = 'rgba(11,16,32,0.08)';
    ctx.fillRect(0,0,width,height);
  }

  // parameters
  const baseSpeed = parseFloat(speedControl.value) || 4;

  for (let i=0;i<boids.length;i++){
    const b = boids[i];
    b.maxSpeed = baseSpeed + (Math.sin((i/boids.length)*Math.PI*2 + t*0.001) * 0.8);
    b.flock(boids, {align:1.0, cohesion:0.9, separation:1.7});
    b.update();
    b.edges(width, height);

    // color hue varies with index and velocity
    const speed = Math.hypot(b.vel.x, b.vel.y);
    const hue = (i * 360 / Math.max(1, boids.length) + (speed - baseSpeed) * 40 + t*0.01) % 360;
    b.draw(ctx, Math.floor(hue), 6 + Math.min(6, speed));
  }

  requestAnimationFrame(loop);
}

document.addEventListener('DOMContentLoaded', init);
"""

# Write files to disk
write_file('index.html', index_html)
write_file('css/style.css', style_css)
write_file('js/boid.js', boid_js)
write_file('js/flock.js', flock_js)
write_file('js/main.js', main_js)

# 2) Spawn verification delegates for each file to check wiring and expected exports/imports.
handles = []
files_to_check = [
    ('index.html', ['<canvas id="flockCanvas">', '<link rel="stylesheet" href="css/style.css"', 'script type="module" src="js/main.js"']),
    ('css/style.css', [':root', '#flockCanvas', '#ui']),
    ('js/boid.js', ['export default class Boid', 'flock(', 'draw(ctx']),
    ('js/flock.js', ["import Boid from './boid.js'", 'export function createFlock']),
    ('js/main.js', ["import Boid from './boid.js'", "import { createFlock } from './flock.js'", "requestAnimationFrame(loop)"])
]

for fname, checks in files_to_check:
    content = read_file(fname)
    # Build a query describing what to check and return PASS/FAIL with reason
    query = f"""Verify this file is correctly wired for the boids app.
Return a single line that begins with PASS or FAIL. If FAIL include a brief reason.
Checks: {checks}
"""
    handles.append(rlm_delegate(
        name=f"check_{fname.replace('/','_')}",
        query=query,
        context=content
    ))

# 3) Wait for checks
results = yield rlm_wait(*handles)

# 4) Inspect outputs and prepare summary
summary_lines = []
all_pass = True
for (fname, checks), res in zip(files_to_check, results):
    line = f"{fname}: {res.strip()}"
    summary_lines.append(line)
    if not res.strip().upper().startswith("PASS"):
        all_pass = False

# 5) Provide final answer: list created files and verification results. If any failed, include file contents snippet.
final_msg = "Created files:\n"
for f,_ in files_to_check:
    final_msg += f" - {f}\n"

final_msg += "\nVerification results:\n"
final_msg += "\n".join(summary_lines)
final_msg += "\n\nHow to run:\n - Open index.html in a modern browser (double-click or serve with a static server).\n - Use the UI to change boid count, speed, and toggle trails. Enjoy colorful, fast-moving boids!\n"

if not all_pass:
    final_msg += "\nSome checks failed. Below are file snippets to help debug:\n"
    for fname, _ in files_to_check:
        content = read_file(fname)
        snippet = content[:1000].replace('\\n','\\n')
        final_msg += f"\n--- {fname} (first 1000 chars) ---\\n{snippet}\\n"

done(final_msg)
```
